import { resultFromThrowable } from '@agentcash/neverthrow';

import { safeAppendFile } from '@/shared/neverthrow/fs';

import { configFile } from './fs';
import { isVerbose } from '@/cli/lib/context';

/**
 * Resolved lazily on first write. `null` means the filesystem is
 * unavailable (e.g. Vercel sandbox) — file logging is skipped.
 */
let logFile: string | null | undefined;

function getLogFile(): string | null {
  if (logFile === undefined) {
    const result = resultFromThrowable(
      'log',
      'log',
      () => configFile('mcp.log'),
      e => ({
        cause: 'log_init' as const,
        message: e instanceof Error ? e.message : String(e),
      })
    );
    logFile = result.isOk() ? result.value : null;
  }
  return logFile;
}

function format(args: unknown[]): string {
  return args
    .map(a =>
      typeof a === 'object' && a !== null ? JSON.stringify(a) : String(a)
    )
    .join(' ');
}

function write(level: string, msg: string, args: unknown[]): void {
  const formatted = args.length ? `${msg} ${format(args)}` : msg;
  const line = `[${new Date().toISOString()}] [${level}] ${formatted}\n`;
  const file = getLogFile();
  if (file) safeAppendFile('log', file, line);
  if (isVerbose()) {
    console.error(`[agentcash] ${formatted}`);
  }
}

export const log = {
  info: (msg: string, ...args: unknown[]) => write('INFO', msg, args),
  error: (msg: string, ...args: unknown[]) => write('ERROR', msg, args),
  debug: (msg: string, ...args: unknown[]) =>
    isVerbose() && write('DEBUG', msg, args),
  get path() {
    return getLogFile();
  },
};
