import {
  readFile,
  writeFile,
  appendFile,
  chmod,
  mkdir,
  mkdtemp,
  rm,
  copyFile,
  cp,
  symlink,
  lstat,
  unlink,
  realpath,
  readdir,
} from 'fs/promises';
import {
  existsSync,
  lstatSync,
  realpathSync,
  rmSync,
  unlinkSync,
} from 'node:fs';

import {
  err,
  resultFromPromise,
  resultFromThrowable,
} from '@agentcash/neverthrow';

import type { BaseFileSystemError } from './types';

const errorType = 'fs';

export const fsErr = (surface: string, error: BaseFileSystemError) =>
  err(errorType, surface, error);

const fsResultFromPromise = <T>(
  surface: string,
  promise: Promise<T>,
  error: (e: unknown) => BaseFileSystemError
) => resultFromPromise(errorType, surface, promise, error);

const fsResultFromThrowable = <T>(
  surface: string,
  fn: () => T,
  error: (e: unknown) => BaseFileSystemError
) => resultFromThrowable(errorType, surface, fn, error);

export const safeReadFile = (
  surface: string,
  path: Parameters<typeof readFile>[0]
) =>
  fsResultFromPromise(surface, readFile(path, 'utf-8'), error => ({
    cause:
      (error as NodeJS.ErrnoException).code === 'ENOENT'
        ? 'file_not_found'
        : 'file_not_readable',
    message: 'Failed to read file',
  }));

export const safeWriteFile = (
  surface: string,
  ...args: Parameters<typeof writeFile>
) =>
  fsResultFromPromise(surface, writeFile(...args), () => ({
    cause: 'file_not_writable',
    message: 'Failed to write file',
  }));

