export const safeReadDirents = (
  surface: string,
  dirPath: Parameters<typeof readdir>[0]
) =>
  fsResultFromPromise(
    surface,
    readdir(dirPath, { encoding: 'utf8', withFileTypes: true }),
    error => ({
      cause:
        (error as NodeJS.ErrnoException).code === 'ENOENT'
          ? 'file_not_found'
          : 'file_not_readable',
      message: 'Failed to read directory',
    })
  );

